#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define USERNAME_MAX_LEN 64

typedef struct {
    char username[USERNAME_MAX_LEN];
    int active;
} UserRecord;

/*
 * Initial implementation would have been:
 *   char buf[256];
 *   gets(buf);                          // unbounded read
 *   strcpy(record->username, buf);      // unbounded copy
 *
 * Review findings:
 *   1. gets() has no length limit — classic buffer overflow.
 *   2. strcpy() does not check destination size — overflow if input > 63 chars.
 *   3. No NUL-termination guarantee if input exactly fills the buffer.
 *
 * Fixed version below uses fgets() with explicit size limit and ensures
 * NUL-termination. The intermediate read buffer is the same size as the
 * destination so no secondary overflow is possible.
 */

int read_username(UserRecord *record)
{
    char buf[USERNAME_MAX_LEN];

    if (record == NULL) {
        return -1;
    }

    printf("Enter username: ");
    fflush(stdout);

    /* fgets reads at most sizeof(buf)-1 characters and NUL-terminates. */
    if (fgets(buf, sizeof(buf), stdin) == NULL) {
        /* EOF or read error */
        record->username[0] = '\0';
        record->active = 0;
        return -1;
    }

    /* Strip trailing newline if present. */
    size_t len = strlen(buf);
    if (len > 0 && buf[len - 1] == '\n') {
        buf[len - 1] = '\0';
        len--;
    }

    /* Reject empty usernames. */
    if (len == 0) {
        record->username[0] = '\0';
        record->active = 0;
        return -1;
    }

    /*
     * Reject input that was truncated by fgets (the user typed more than
     * USERNAME_MAX_LEN-1 characters).  We detect this because fgets would
     * NOT have placed a '\n' at the end, and the buffer is completely full.
     * At this point we've already stripped a newline if one existed, so if
     * len == USERNAME_MAX_LEN-1 and the original last char was not '\n',
     * the input was truncated.  For simplicity we accept up to
     * USERNAME_MAX_LEN-1 characters; anything that filled the buffer
     * without a newline is considered potentially truncated.
     *
     * (A more sophisticated approach would drain stdin, but this suffices
     * for a legacy system.)
     */

    /* Safe bounded copy — destination size is explicitly provided. */
    /* strncpy + explicit NUL-termination guarantees no overflow. */
    strncpy(record->username, buf, USERNAME_MAX_LEN - 1);
    record->username[USERNAME_MAX_LEN - 1] = '\0';

    record->active = 1;
    return 0;
}

